   private async setupHotReloadModular(modularDir: string): Promise<void> {
     const fragmentFiles = await this.getAllFragmentFiles(modularDir);

     for (const file of fragmentFiles) {
       const watcher = watch(file, { persistent: false });

       watcher.on('change', async () => {
         this.emit('configChanging', {
           type: 'category',
           filepath: file,
           fragment: basename(dirname(file)) // e.g., 'categories', '_base', root
         });

         // Recompose entire config (any fragment change invalidates all)
         await this.loadCategoryConfigurationModular(modularDir);

         this.emit('configChanged', { type: 'category', filepath: file });
       });

       this.watchers.set(file, watcher);
     }
   }
