   294→### Phase 2: Configuration Loader Module (3 hours)
   295→
   296→**Objective**: Create runtime composition layer with template inheritance support
   297→
   298→**File**: `packages/classification-engine/src/config/config-composer.ts`
   299→
   300→**Architecture**:
   301→
   302→```typescript
   303→/**
   304→ * Configuration Composer - Runtime composition with template inheritance
   305→ *
   306→ * Load order:
   307→ * 1. Load category template (_base/category-template.json)
   308→ * 2. Load global fragments (settings, attributes, ai_config, domains)
   309→ * 3. Load category fragments (categories/*.json)
   310→ * 4. Apply template inheritance (merge category + template)
   311→ * 5. Compose into final CategoryConfiguration object
   312→ * 6. Validate against existing Zod schema
   313→ * 7. Cache in-memory (invalidate on any fragment change)
   314→ */
   315→
   316→export interface ComposerOptions {
   317→  configDir?: string;
   318→  enableCaching?: boolean;
   319→  cacheTtlMs?: number;
   320→}
   321→
   322→export class ConfigurationComposer {
   323→  private templateCache: CategoryTemplate | null = null;
   324→  private composedConfigCache: CategoryConfiguration | null = null;
   325→  private fragmentHashes: Map<string, string> = new Map();
   326→
   327→  /**
   328→   * Main composition function - assembles final config from fragments
   329→   */
   330→  async composeConfiguration(): Promise<CategoryConfiguration> {
   331→    // 1. Check cache validity (compare file hashes)
   332→    if (await this.isCacheValid()) {
   333→      return this.composedConfigCache!;
   334→    }
   335→
   336→    // 2. Load all fragments in parallel
   337→    const [template, settings, attributes, aiConfig, domains, categories] = await Promise.all([
   338→      this.loadCategoryTemplate(),
   339→      this.loadSettings(),
   340→      this.loadAttributes(),
   341→      this.loadAiConfig(),
   342→      this.loadDomains(),
   343→      this.loadCategories(),
   344→    ]);
   345→
   346→    // 3. Apply template inheritance to categories
   347→    const inheritedCategories = categories.map((cat) => this.applyTemplateInheritance(cat, template));
   348→
   349→    // 4. Compose final configuration object
   350→    const composed = this.assembleConfiguration({
   351→      settings,
   352→      attributes,
   353→      aiConfig,
   354→      domains,
   355→      categories: inheritedCategories,
   356→    });
   357→
   358→    // 5. Validate against existing schema
   359→    const validated = validateCategoryConfiguration(composed);
   360→
   361→    // 6. Cache result
   362→    this.composedConfigCache = validated;
   363→    await this.updateFragmentHashes();
   364→
   365→    return validated;
   366→  }
   367→
   368→  /**
   369→   * Apply template inheritance with merge strategy
   370→   */
   371→  private applyTemplateInheritance(category: CategoryFragment, template: CategoryTemplate): CategoryDefinition {
   372→    const merged = { ...template.structure };
   373→
   374→    for (const [field, strategy] of Object.entries(template.mergeStrategy)) {
   375→      if (field in category) {
   376→        if (strategy === 'override') {
   377→          merged[field] = category[field];
   378→        } else if (strategy === 'merge-deep') {
   379→          merged[field] = this.deepMerge(merged[field], category[field]);
   380→        }
   381→      }
   382→    }
   383→
   384→    return merged as CategoryDefinition;
   385→  }
   386→
   387→  /**
   388→   * Deep merge with category-specific overrides
   389→   */
   390→  private deepMerge(base: unknown, override: unknown): unknown {
   391→    // Implementation: recursive merge with array override (not concat)
   392→    // ...
   393→  }
   394→
   395→  /**
   396→   * Load individual fragments (parallel-safe)
   397→   */
   398→  private async loadCategoryTemplate(): Promise<CategoryTemplate> {
   399→    /* ... */
   400→  }
   401→  private async loadSettings(): Promise<GlobalSettings> {
   402→    /* ... */
   403→  }
   404→  private async loadAttributes(): Promise<AttributeDefinitions> {
   405→    /* ... */
   406→  }
   407→  private async loadAiConfig(): Promise<AiConfiguration> {
   408→    /* ... */
   409→  }
   410→  private async loadDomains(): Promise<DomainConfiguration> {
   411→    /* ... */
   412→  }
   413→  private async loadCategories(): Promise<CategoryFragment[]> {
   414→    // Reads all files from categories/ directory
   415→    // Returns array of category fragments
   416→  }
   417→
   418→  /**
   419→   * Assemble final configuration object
   420→   */
   421→  private assembleConfiguration(fragments: AllFragments): CategoryConfiguration {
   422→    return {
   423→      version: '2.0.0',
   424→      lastModified: new Date().toISOString(),
   425→      hash: this.calculateComposedHash(fragments),
   426→      processingConfig: {
   427→        version: 2,
   428→        settings: fragments.settings,
   429→        attributes: fragments.attributes,
   430→        aiConfig: fragments.aiConfig,
   431→        domainConfig: fragments.domains,
   432→        topLevelCategories: this.categoriesToObject(fragments.categories),
   433→        categorySignals: this.buildCategorySignals(fragments.categories),
   434→      },
   435→    };
   436→  }
   437→
   438→  /**
   439→   * Cache validation - check if any fragment changed
   440→   */
   441→  private async isCacheValid(): Promise<boolean> {
   442→    if (!this.composedConfigCache) return false;
   443→
   444→    const files = await this.getAllFragmentFiles();
   445→    for (const file of files) {
   446→      const currentHash = await this.calculateFileHash(file);
   447→      const cachedHash = this.fragmentHashes.get(file);
   448→      if (currentHash !== cachedHash) return false;
   449→    }
   450→
   451→    return true;
   452→  }
   453→}
   454→
   455→/**
   456→ * Integration with existing ConfigurationLoader
   457→ */
   458→export async function loadCategoryConfigurationModular(
   459→  options?: ComposerOptions
   460→): Promise<ConfigLoadResult<CategoryConfiguration>> {
   461→  const composer = new ConfigurationComposer(options);
   462→  const config = await composer.composeConfiguration();
   463→
   464→  // Return in ConfigLoadResult format for compatibility
   465→  return {
   466→    config,
   467→    hash: config.hash,
   468→    lastModified: new Date(config.lastModified),
   469→    validationPassed: true,
   470→    validationErrors: [],
   471→    loadTime: 0, // Tracked separately
   472→  };
   473→}
   474→```
