   758→   private async setupHotReloadModular(modularDir: string): Promise<void> {
   759→     const fragmentFiles = await this.getAllFragmentFiles(modularDir);
   760→
   761→     for (const file of fragmentFiles) {
   762→       const watcher = watch(file, { persistent: false });
